mapper.select:
select * from (select * from nx_goods


        and nx_goods_name = #{name}


        and nx_goods_standardname = #{standard}


        and nx_goods_standard_weight = #{standardWeight}


        and nx_goods_brand = #{brand}


        and nx_goods_grand_id = #{grandId}


        and nx_goods_great_grand_id = #{greatGrandId}


        and nx_goods_great_grand_id in

            #{id}



        and nx_goods_father_id = #{fatherId}


        and nx_goods_apply_nx_distributer_id = #{disId}


        and nx_goods_level = #{level}


        and nx_goods_is_oldest_son = #{isOldestSon}


        and nx_goods_is_hidden = #{isHidden}


order by nx_goods_sort, nx_goods_sons_sort

    limit #{offset}, #{limit}

) as g
left join nx_standard as st on st.nx_s_goods_id = g.nx_goods_id
left join nx_alias as na on na.nx_als_goods_id = g.nx_goods_id
order by g.nx_goods_sort, g.nx_goods_sons_sort

select count(*) from nx_goods


        and nx_goods_great_grand_id = #{greatGrandId}


        and nx_goods_is_hidden = #{isHidden}

select * from
(select * from nx_goods

    where nx_goods_father_id = #{fatherId}

order by nx_goods_sort, nx_goods_sons_sort

    limit #{offset}, #{limit}
)as g
left join nx_standard as s on g.nx_goods_id = s.nx_s_goods_id
left join nx_alias as na on na.nx_als_goods_id = g.nx_goods_id
order by g.nx_goods_sort, g.nx_goods_sons_sort

select count(*)
from nx_goods
where nx_goods_father_id = #{fatherId}

select *
from nx_goods
where nx_goods_father_id = #{type}

select * from nx_goods


        and nx_goods_name = #{goodsName}


        and nx_goods_pinyin = #{goodsPinyin}



        and nx_goods_brand = #{goodsBrand}


        and nx_goods_detail = #{goodsDetail}


        and nx_goods_standardname = #{goodsStandard}


        and nx_goods_standard_weight = #{standardWeight}


        and nx_goods_place = #{place}


        and nx_goods_sort = #{sort}


        and nx_goods_level = #{level}


        and nx_goods_father_id = #{fatherId}


        and nx_goods_father_id != #{notEqualFatherId}


        and nx_goods_carton_unit = #{unitName}


        and nx_goods_items_per_carton = #{items}

select * from nx_goods

    where nx_goods_father_id = #{fatherId}

order by nx_goods_sort

    limit #{offset}, #{limit}

select MAX(nx_goods_sort)
from nx_goods
where nx_goods_father_id = #{nxDfgNxGoodsId}

select MAX(nx_goods_id)
from nx_goods
where nx_goods_father_id = #{nxDfgNxGoodsId}

SELECT limited_goods.*, gds.*, ns.*, gdg.*, gddg.*, gdo.*, gs.* FROM ( SELECT ng.nx_goods_id AS nx_goods_id, ng.nx_goods_name AS nx_goods_name, ng.nx_goods_standardname AS nx_goods_standardname, ng.nx_goods_standard_weight AS nx_goods_standard_weight, ng.nx_goods_father_id AS nx_goods_father_id, ng.nx_goods_grand_id AS nx_goods_grand_id, ng.nx_goods_great_grand_id AS nx_goods_great_grand_id, ng.nx_goods_sort AS nx_goods_sort, ng.nx_goods_sons_sort AS nx_goods_sons_sort, ng.nx_goods_file AS nx_goods_file, ng.nx_goods_file_big AS nx_goods_file_big, ng.nx_goods_detail AS nx_goods_detail, f.nx_goods_id AS father_nx_goods_id, f.nx_goods_father_id AS father_nx_goods_father_id, f.nx_goods_name AS father_nx_goods_name, f.nx_goods_sort AS father_nx_goods_sort, f.nx_goods_sons_sort AS father_nx_goods_sons_sort,
g.nx_goods_id AS grand_nx_goods_id, g.nx_goods_father_id AS grand_nx_goods_father_id, g.nx_goods_sort AS grand_nx_goods_sort, g.nx_goods_sons_sort AS grand_nx_goods_sons_sort, gg.nx_goods_id AS great_nx_goods_id, gg.nx_goods_father_id AS great_nx_goods_father_id, gg.nx_goods_sort AS great_nx_goods_sort, gg.nx_goods_sons_sort AS great_nx_goods_sons_sort
FROM nx_goods AS ng LEFT JOIN nx_goods AS f ON f.nx_goods_id = ng.nx_goods_father_id LEFT JOIN nx_goods AS g ON g.nx_goods_id = f.nx_goods_father_id LEFT JOIN nx_goods AS gg ON gg.nx_goods_id = g.nx_goods_father_id
gg.nx_goods_id = #{grandId}
AND ng.nx_goods_is_hidden = #{isHidden}
ORDER BY gg.nx_goods_sort, g.nx_goods_sort, f.nx_goods_sort, ng.nx_goods_sort, ng.nx_goods_sons_sort
LIMIT #{offset}, #{limit} ) AS limited_goods
LEFT JOIN nx_standard AS ns ON ns.nx_s_goods_id = limited_goods.nx_goods_id
LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = limited_goods.nx_goods_id AND gdg.gb_dg_distributer_id = #{gbDisId}
LEFT JOIN gb_distributer_standard as gs on gs.gb_DS_dis_goods_id = gdg.gb_distributer_goods_id
LEFT JOIN gb_department_dis_goods AS gddg ON gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id AND gddg.gb_DDG_department_id = #{gbDepId}
LEFT JOIN gb_department_orders AS gdo ON gdo.gb_DO_nx_goods_id = limited_goods.nx_goods_id AND gdo.gb_DO_status < 3 AND gdo.gb_DO_department_id = #{gbDepId} LEFT JOIN gb_department_goods_stock as gds on gds.gb_dgs_gb_dep_dis_goods_id = gddg.gb_department_dis_goods_id
ORDER BY limited_goods.great_nx_goods_sort, limited_goods.grand_nx_goods_sort, limited_goods.father_nx_goods_sort, limited_goods.nx_goods_sort, limited_goods.nx_goods_sons_sort

SELECT * FROM nx_goods AS ng LEFT JOIN nx_standard AS ns ON ns.nx_s_goods_id = ng.nx_goods_id LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = ng.nx_goods_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = ng.nx_goods_id AND gb_dg_distributer_id = #{gbDisId} left join gb_distributer_standard as gds on gds.gb_DS_dis_goods_id = gdg.gb_distributer_goods_id LEFT JOIN gb_department_dis_goods AS gddg ON gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id AND gddg.gb_DDG_department_id = #{gbDepId} LEFT JOIN gb_department_orders AS gdo ON gdo.gb_DO_nx_goods_id = ng.nx_goods_id AND gdo.gb_DO_status < 3 AND gdo.gb_DO_department_id = #{gbDepId}
AND ng.nx_goods_grand_id = #{grandId}
AND ng.nx_goods_is_hidden = #{isHidden}
ORDER BY ng.nx_goods_great_grand_id, ng.nx_goods_grand_id, ng.nx_goods_sort, ng.nx_goods_father_id, ng.nx_goods_sons_sort

SELECT * FROM ( SELECT * FROM nx_goods AS ng LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = ng.nx_goods_id where ng.nx_goods_is_hidden = #{isHidden} and ng.nx_goods_level = 3 and ( ng.nx_goods_name like concat('%', #{searchStr}, '%') or na.nx_alias_name like concat('%', #{searchStr}, '%') )
ORDER BY ng.nx_goods_great_grand_id, ng.nx_goods_grand_id, ng.nx_goods_father_id, ng.nx_goods_sort ) AS limited_goods LEFT JOIN nx_standard AS ns ON ns.nx_s_goods_id = limited_goods.nx_goods_id LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = limited_goods.nx_goods_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = limited_goods.nx_goods_id and gdg.gb_dg_distributer_id = #{gbDisId}
LEFT JOIN gb_distributer_standard as gds on gds.gb_DS_dis_goods_id = gdg.gb_distributer_goods_id LEFT JOIN gb_distributer_alias as gda on gda.gb_DA_dis_goods_id = gdg.gb_distributer_goods_id left join gb_department_dis_goods as gddg on gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id and gddg.gb_DDG_department_id = #{gbDepId} LEFT JOIN gb_department_orders AS gdo ON gdo.gb_DO_nx_goods_id = limited_goods.nx_goods_id AND gdo.gb_DO_status < 3 AND gdo.gb_DO_department_id = #{gbDepId} order by limited_goods.nx_goods_father_id, limited_goods.nx_goods_sort, limited_goods.nx_goods_sons_sort

SELECT *
FROM (
         SELECT *
         FROM nx_goods AS ng
                  LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = ng.nx_goods_id
         where ng.nx_goods_is_hidden = #{isHidden}
           and ng.nx_goods_level = 3

           and (ng.nx_goods_py = #{searchPinyin}
             or ng.nx_goods_pinyin = #{searchPinyin}
             or ng.nx_goods_name = #{searchStr}
             or na.nx_alias_name = #{searchStr}
             )

         ORDER BY ng.nx_goods_great_grand_id, ng.nx_goods_grand_id, ng.nx_goods_father_id, ng.nx_goods_sort
     ) AS limited_goods
         LEFT JOIN nx_standard AS ns ON ns.nx_s_goods_id = limited_goods.nx_goods_id
         LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = limited_goods.nx_goods_id
         LEFT JOIN gb_distributer_goods AS gdg
                   ON gdg.gb_dg_nx_goods_id = limited_goods.nx_goods_id and gdg.gb_dg_distributer_id = #{gbDisId}

         LEFT JOIN gb_distributer_standard as gds on gds.gb_DS_dis_goods_id = gdg.gb_distributer_goods_id
         LEFT JOIN gb_distributer_alias as gda on gda.gb_DA_dis_goods_id = gdg.gb_distributer_goods_id
         left join gb_department_dis_goods as gddg
                   on gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id and gddg.gb_DDG_department_id = #{gbDepId}
         LEFT JOIN gb_department_orders AS gdo ON gdo.gb_DO_nx_goods_id = limited_goods.nx_goods_id
    AND gdo.gb_DO_status < 3 AND gdo.gb_DO_department_id = #{gbDepId}
order by limited_goods.nx_goods_father_id, limited_goods.nx_goods_sort, limited_goods.nx_goods_sons_sort

SELECT * FROM ( SELECT * FROM nx_goods AS ng LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = ng.nx_goods_id where ng.nx_goods_is_hidden = #{isHidden} and ng.nx_goods_level = 3 and (ng.nx_goods_py like concat('%', #{searchPinyin}, '%') or ng.nx_goods_pinyin like concat('%', #{searchPinyin}, '%') )
ORDER BY ng.nx_goods_great_grand_id, ng.nx_goods_grand_id, ng.nx_goods_father_id, ng.nx_goods_sort ) AS limited_goods LEFT JOIN nx_standard AS ns ON ns.nx_s_goods_id = limited_goods.nx_goods_id LEFT JOIN nx_alias AS na ON na.nx_als_goods_id = limited_goods.nx_goods_id LEFT JOIN gb_distributer_goods AS gdg ON gdg.gb_dg_nx_goods_id = limited_goods.nx_goods_id and gdg.gb_dg_distributer_id = #{gbDisId}
LEFT JOIN gb_distributer_standard as gds on gds.gb_DS_dis_goods_id = gdg.gb_distributer_goods_id LEFT JOIN gb_distributer_alias as gda on gda.gb_DA_dis_goods_id = gdg.gb_distributer_goods_id left join gb_department_dis_goods as gddg on gddg.gb_DDG_dis_goods_id = gdg.gb_distributer_goods_id and gddg.gb_DDG_department_id = #{gbDepId} LEFT JOIN gb_department_orders AS gdo ON gdo.gb_DO_nx_goods_id = limited_goods.nx_goods_id AND gdo.gb_DO_status < 3 AND gdo.gb_DO_department_id = #{gbDepId} order by limited_goods.nx_goods_father_id, limited_goods.nx_goods_sort, limited_goods.nx_goods_sons_sort

select COUNT(*) from nx_goods


        and nx_goods_great_grand_id = #{greatGrandId}


        and nx_goods_is_hidden = #{isHidden}

select dg.nx_goods_id from nx_goods as dg left join nx_goods as f on f.nx_goods_id = dg.nx_goods_father_id left join nx_goods as g on g.nx_goods_id = f.nx_goods_father_id left join nx_goods as gg on gg.nx_goods_id = g.nx_goods_father_id
AND dg.nx_goods_is_hidden = #{isHidden}
AND dg.nx_goods_great_grand_id = #{greatGrandId}
and dg.nx_goods_level = 3
ORDER BY gg.nx_goods_sort, g.nx_goods_sort, f.nx_goods_sort, dg.nx_goods_sort, dg.nx_goods_sons_sort
